  ('diplomatic-0471a791-moex-00344', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-112-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '依司法院大法官解釋，有關人民服兵役義務，下列敘述何者錯誤？', '["有關人民服兵役之重要事項，應由立法者斟酌國家安全、社會發展之需要，以法律定之", "後備軍人居住處所遷移，無故不依規定申報者，即處以刑事罰，違憲", "妨害兵役治罪條例，課予後備軍人就居住處所遷移依規定向相關機關為申報之義務，不違憲", "男子服兵役之義務，並無違反人性尊嚴，也無違反平等原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:16+00:00", "source_pdf_sha1": "666ca31ec295", "answer_pdf_sha1": "0b8d6d62dd21", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00345', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-112-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '憲法增修條文有關行政院院長與總統、副總統之規定，下列敘述何者正確？', '["行政院院長由總統提名，經立法院同意任命之", "總統或副總統因故不能視事時，由行政院院長代行其職權", "總統、副總統均缺位時，由行政院院長召集國民大會補選總統、副總統", "立法院通過不信任案後，行政院院長得呈請總統解散立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:16+00:00", "source_pdf_sha1": "666ca31ec295", "answer_pdf_sha1": "0b8d6d62dd21", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
